/* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
}
function dispose$GridVoucherDetail$(g) {
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
}

function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'GenerateLineNumber':
      if (f._action == 'View') break;
      if (!f.validFields('so_ct0')) break;
      if (f.getItemValue('stt_rec0') != '') {
        var curLine = '', l1 = g._getColumnOrder('line_nbr0');
        for (var i = 1; i <= g._rowCount; i++) {
          curLine += (curLine != '' ? ',' : '') + g._getItemValue(i, l1);
        }
        g.request(g, 'GenerateLineNumber', 'GenerateLineNumber', [], ['stt_rec0', 'ngay_ct0', 'stt_rec1', 'ngay_ct1', ['curLine', 'String', curLine]]);
      }
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm, r;
  switch (context) {
    case 'GenerateLineNumber':
      if (result.length <= 0) return;

      var first = true, l0 = g._getColumnOrder('line_nbr0'), l1 = g._getColumnOrder('line_nbr1');
      for(var i = 0; i < result.length; i++) {
        var ins = true, row = g._rowCount, d = result[i];
        if (first && row > 0) if (g.blankMemvar(row)) {ins = false; first = false;}
        if (ins) g._appendRow(null, true);
        row = g._rowCount;

        var o = g._getItem(row, l0);
        o.row = row;
        g.setItemGridBehavior(o, [['line_nbr0', d[1], null, false], ['line_nbr1', d[2], null, false]]);
      }
      break;
    default:
      break;
  }
}
/* </flatten> */
